class Solution {
public:
    int maxFreq(string s, int maxLetters, int minSize, int maxSize) {
        int max = 0;
        unordered_map<string, int> freq;
        for (int i = 0; i <= s.size() - maxSize; i++) {
            for (int j = minSize; j <= maxSize && i + j <= s.size(); j++) {
                string substr = s.substr(i, j);
                if (substr.size() == j && substr.size() <= maxLetters) {
                    freq[substr]++;
                    max = max > freq[substr] ? max : freq[substr];
                }
            }
        }
        return max;
    }
};
